code.C:
#include <stdio.h>
#include <math.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        printf("%d\n", (int)sqrt((double)N));
    }
    return 0;
}

