    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long N = sc.nextLong();
            System.out.println((int)Math.floor(Math.sqrt(N)));
        }
        sc.close();
    }
}

