const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
if (input.length === 0) process.exit();
let idx = 0;
const T = parseInt(input[idx++], 10);
let results = [];
for (let i = 0; i < T; i++) {
  const N = BigInt(input[idx++]);
  // Use Number for sqrt because N <= 10000 fits safely
  const sqrtVal = Math.floor(Math.sqrt(Number(N)));
  results.push(String(sqrtVal));
}
console.log(results.join('\n'));

